import{_ as n,o as s,c as a,ag as t}from"./chunks/framework.BBBcTwIo.js";const m=JSON.parse('{"title":"3D Scene System","description":"","frontmatter":{},"headers":[],"relativePath":"three-scene.md","filePath":"three-scene.md"}'),o={name:"three-scene.md"};function i(l,e,p,r,d,c){return s(),a("div",null,[...e[0]||(e[0]=[t(`<h1 id="_3d-scene-system" tabindex="-1">3D Scene System <a class="header-anchor" href="#_3d-scene-system" aria-label="Permalink to &quot;3D Scene System&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The DYO 3D scene uses <strong>React Three Fiber (R3F)</strong> to render an interactive WebGL scene. The scene is mounted once at the root layout and persists across all route navigations, avoiding expensive WebGL context recreation.</p><h2 id="scene-graph" tabindex="-1">Scene Graph <a class="header-anchor" href="#scene-graph" aria-label="Permalink to &quot;Scene Graph&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Canvas (React Three Fiber)</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── CameraController</span></span>
<span class="line"><span>│   └── OrbitControls (damped, constrained)</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>└── Scene.tsx</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── Lighting</span></span>
<span class="line"><span>    │   ├── AmbientLight (intensity: 0.6)</span></span>
<span class="line"><span>    │   ├── HemisphereLight (intensity: 0.8, sky→ground bounce)</span></span>
<span class="line"><span>    │   ├── SpotLight &quot;Key&quot; (intensity: 2.5, position: [-10, 12, 12])</span></span>
<span class="line"><span>    │   └── SpotLight &quot;Rim&quot; (intensity: 2, position: [5, 5, -5])</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── Environment</span></span>
<span class="line"><span>    │   ├── AtmosphericSky (gradient sky dome)</span></span>
<span class="line"><span>    │   ├── SunRays (dust particle effect)</span></span>
<span class="line"><span>    │   ├── Sparkles (floating particles)</span></span>
<span class="line"><span>    │   ├── Fog (#ADCCE7, near: 9, far: 48 desktop / 24 mobile)</span></span>
<span class="line"><span>    │   └── HDRI (/hdri/spring.hdr, low-res)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── GrassFloor</span></span>
<span class="line"><span>    │   ├── Textured plane (/textures/three/grass/*)</span></span>
<span class="line"><span>    │   ├── Normal maps + AO</span></span>
<span class="line"><span>    │   └── ContactShadows (baked at ground level)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    └── HeadstoneAssembly</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ├── ShapeSwapper</span></span>
<span class="line"><span>        │   SVG outline → extruded 3D geometry</span></span>
<span class="line"><span>        │   Material from headstoneMaterialUrl (WebP texture)</span></span>
<span class="line"><span>        │   Supports headstone, plaque, and slant geometries</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ├── Surface Content (on headstone face)</span></span>
<span class="line"><span>        │   ├── HeadstoneInscription[] (3D text with fonts)</span></span>
<span class="line"><span>        │   ├── MotifModel[] (SVG ornaments as canvas textures)</span></span>
<span class="line"><span>        │   ├── ImageModel[] (photos with drag/crop)</span></span>
<span class="line"><span>        │   ├── AdditionModel[] (3D GLB models)</span></span>
<span class="line"><span>        │   └── EmblemModel[] (PNG-based logos)</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ├── HeadstoneBaseAuto</span></span>
<span class="line"><span>        │   Auto-sized pedestal base</span></span>
<span class="line"><span>        │   Width = headstone width × 1.4 multiplier</span></span>
<span class="line"><span>        │   Own material from baseMaterialUrl</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ├── LedgerSlab (full monument only)</span></span>
<span class="line"><span>        │   Horizontal ground-level slab</span></span>
<span class="line"><span>        │   Own dimensions &amp; material</span></span>
<span class="line"><span>        │   └── LedgerSurfaceContent</span></span>
<span class="line"><span>        │       ├── HeadstoneInscription[] (ledger text)</span></span>
<span class="line"><span>        │       ├── ImageModel[] (ledger images)</span></span>
<span class="line"><span>        │       └── MotifModel[] (ledger motifs)</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ├── KerbsetBorder (full monument only)</span></span>
<span class="line"><span>        │   Grave plot border frame (4 corners + sides)</span></span>
<span class="line"><span>        │   Own material from kerbsetMaterialUrl</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        └── Selection Indicators</span></span>
<span class="line"><span>            └── RotatingBoxOutline[] (animated corner brackets)</span></span></code></pre></div><h2 id="mount-chain" tabindex="-1">Mount Chain <a class="header-anchor" href="#mount-chain" aria-label="Permalink to &quot;Mount Chain&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>app/layout.tsx</span></span>
<span class="line"><span>  └── ClientLayout</span></span>
<span class="line"><span>       └── ConditionalCanvas.tsx ← Route-aware visibility gate</span></span>
<span class="line"><span>            └── ThreeScene.tsx ← Canvas wrapper + loading + rotation controls</span></span>
<span class="line"><span>                 └── &lt;Canvas&gt; (R3F)</span></span>
<span class="line"><span>                      └── Scene.tsx ← Core scene with lights, environment, assembly</span></span></code></pre></div><h3 id="conditionalcanvas-route-rules" tabindex="-1">ConditionalCanvas Route Rules <a class="header-anchor" href="#conditionalcanvas-route-rules" aria-label="Permalink to &quot;ConditionalCanvas Route Rules&quot;">​</a></h3><p>The canvas is <strong>shown</strong> on these routes:</p><ul><li><code>/select-size</code>, <code>/select-material</code>, <code>/select-additions</code></li><li><code>/select-motifs</code>, <code>/select-border</code>, <code>/select-emblems</code></li><li><code>/inscriptions</code>, <code>/select-images</code></li></ul><p>The canvas is <strong>hidden</strong> (but stays mounted) on:</p><ul><li><code>/</code>, <code>/designs/*</code>, <code>/check-price</code>, <code>/select-product</code></li><li><code>/select-shape</code>, <code>/my-account</code>, <code>/products/*</code></li></ul><h2 id="key-components" tabindex="-1">Key Components <a class="header-anchor" href="#key-components" aria-label="Permalink to &quot;Key Components&quot;">​</a></h2><h3 id="shapeswapper-components-three-headstone-shapeswapper-tsx" tabindex="-1">ShapeSwapper (<code>components/three/headstone/ShapeSwapper.tsx</code>) <a class="header-anchor" href="#shapeswapper-components-three-headstone-shapeswapper-tsx" aria-label="Permalink to &quot;ShapeSwapper (\`components/three/headstone/ShapeSwapper.tsx\`)&quot;">​</a></h3><p>Loads SVG shapes from <code>/public/shapes/</code> and extrudes them into 3D geometry:</p><ol><li>Fetches SVG file (e.g., <code>/shapes/headstones/serpentine.svg</code>)</li><li>Parses SVG paths into Three.js <code>Shape</code> objects</li><li>Extrudes to 3D with <code>ExtrudeGeometry</code></li><li>Applies granite texture from <code>headstoneMaterialUrl</code></li><li>Exposes <code>tabletRef</code> and <code>headstoneMeshRef</code> for raycasting</li></ol><h3 id="headstoneinscription-components-headstoneinscription-tsx" tabindex="-1">HeadstoneInscription (<code>components/HeadstoneInscription.tsx</code>) <a class="header-anchor" href="#headstoneinscription-components-headstoneinscription-tsx" aria-label="Permalink to &quot;HeadstoneInscription (\`components/HeadstoneInscription.tsx\`)&quot;">​</a></h3><p>Renders 3D text on monument surfaces:</p><ul><li>Uses <code>@react-three/drei</code> Text component (SDF text rendering)</li><li>Supports multiple font families from <code>/public/fonts/</code></li><li>Position in mm-center coordinate space</li><li>Draggable on the headstone face via raycaster</li><li>Surfaces: <code>&#39;headstone&#39;</code> | <code>&#39;base&#39;</code> | <code>&#39;ledger&#39;</code></li></ul><h3 id="motifmodel-components-three-motifmodel-tsx" tabindex="-1">MotifModel (<code>components/three/MotifModel.tsx</code>) <a class="header-anchor" href="#motifmodel-components-three-motifmodel-tsx" aria-label="Permalink to &quot;MotifModel (\`components/three/MotifModel.tsx\`)&quot;">​</a></h3><p>Renders SVG ornaments as textured planes:</p><ul><li>SVG → Canvas → CanvasTexture pipeline</li><li><code>flipY=false</code> with <code>scaleY = planeHeight * -1</code> convention</li><li>Supports colors: black, white, gold, silver</li><li>Sandblasted effect for &quot;Traditional Engraved&quot; products</li><li>Click to select → floating edit panel</li><li>Drag to reposition on surface</li></ul><h3 id="imagemodel-components-three-imagemodel-tsx" tabindex="-1">ImageModel (<code>components/three/ImageModel.tsx</code>) <a class="header-anchor" href="#imagemodel-components-three-imagemodel-tsx" aria-label="Permalink to &quot;ImageModel (\`components/three/ImageModel.tsx\`)&quot;">​</a></h3><p>Renders uploaded photos on monument surfaces:</p><ul><li>Supports crop, resize, rotate</li><li>Grayscale conversion for laser etching</li><li>Drag planes computed via raycaster</li><li>Photo placeholder asset: <code>vitreous-enamel-image.png</code></li></ul><h3 id="additionmodel-components-three-additionmodel-tsx" tabindex="-1">AdditionModel (<code>components/three/AdditionModel.tsx</code>) <a class="header-anchor" href="#additionmodel-components-three-additionmodel-tsx" aria-label="Permalink to &quot;AdditionModel (\`components/three/AdditionModel.tsx\`)&quot;">​</a></h3><p>Renders 3D objects (vases, statues, crucifixes):</p><ul><li>Loads <code>.glb</code> models from <code>/public/additions/</code></li><li>Positioned relative to monument base</li><li>Size variants with different pricing</li><li>Drag to reposition</li></ul><h2 id="selection-system" tabindex="-1">Selection System <a class="header-anchor" href="#selection-system" aria-label="Permalink to &quot;Selection System&quot;">​</a></h2><p>When a user clicks on a 3D object:</p><ol><li><code>Scene.tsx</code> <code>handleCanvasClick</code> fires</li><li>Raycaster determines which mesh was hit</li><li>Store&#39;s <code>selected</code> state updates (<code>&#39;headstone&#39;</code> | <code>&#39;base&#39;</code> | <code>&#39;ledger&#39;</code> | <code>&#39;kerbset&#39;</code>)</li><li><code>RotatingBoxOutline</code> renders animated corner brackets around selected object</li><li>For content items (motifs, images, etc.), the corresponding <code>selectedXxxId</code> updates</li><li>Floating edit panel opens via <code>SceneOverlayController</code></li></ol><h2 id="coordinate-system" tabindex="-1">Coordinate System <a class="header-anchor" href="#coordinate-system" aria-label="Permalink to &quot;Coordinate System&quot;">​</a></h2><p>All positions are in <strong>millimeters</strong> with origin at <strong>headstone center</strong>:</p><ul><li><strong>X</strong>: Left (−) to Right (+)</li><li><strong>Y</strong>: Bottom (−) to Top (+)</li><li><strong>Z</strong>: Back (−) to Front (+)</li></ul><p>Three.js scene uses meters internally. Conversion: <code>1 unit = headstoneHeightMm / 1000</code>.</p><h2 id="environment-lighting" tabindex="-1">Environment &amp; Lighting <a class="header-anchor" href="#environment-lighting" aria-label="Permalink to &quot;Environment &amp; Lighting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Setting</th><th>Value</th></tr></thead><tbody><tr><td>Sky top color</td><td>RGB(0.4, 0.7, 1.0)</td></tr><tr><td>Grass dark color</td><td>RGB(0.3, 0.5, 0.2)</td></tr><tr><td>Fog color</td><td>#ADCCE7 (pale blue)</td></tr><tr><td>Fog near/far (desktop)</td><td>9 / 48</td></tr><tr><td>Fog near/far (mobile)</td><td>9 / 24</td></tr><tr><td>HDRI</td><td><code>/hdri/spring.hdr</code></td></tr><tr><td>Camera 2D tilt</td><td>12.6°</td></tr><tr><td>Camera 2D distance</td><td>10 units</td></tr><tr><td>Animation lerp factor</td><td>0.25</td></tr></tbody></table><h2 id="performance-considerations" tabindex="-1">Performance Considerations <a class="header-anchor" href="#performance-considerations" aria-label="Permalink to &quot;Performance Considerations&quot;">​</a></h2><ul><li><strong>Persistent canvas</strong>: Never unmounted, preserves WebGL context</li><li><strong>Optimized imports</strong>: <code>optimizePackageImports</code> in <code>next.config.ts</code> for Three.js</li><li><strong>Texture format</strong>: WebP for granite textures (smaller than JPEG)</li><li><strong>SVG caching</strong>: <code>svg-cache.ts</code> caches parsed SVG shapes</li><li><strong>Texture preloading</strong>: <code>preload-texture.ts</code> warms GPU textures</li><li><strong>Contact shadows</strong>: Baked (not real-time) for ground shadows</li><li><strong>Instancing</strong>: Monument parts reuse geometries where possible</li></ul>`,39)])])}const u=n(o,[["render",i]]);export{m as __pageData,u as default};
